		// 	p->_kpt.kfreewalk( stackbase - hsai::page_size );
		// }

		p->_pt.set_base( 0 );
		// p->_kpt.set_base( 0 );
		p->_prog_section_cnt = 0;
		p->_sz				 = 0;
		p->_heap_ptr		 = 0;
		p->_pid				 = 0;
		p->parent			 = 0;
		p->_chan			 = 0;
		p->_name[0]			 = 0;
		p->_killed			 = 0;
		p->_xstate			 = 0;
		p->_state			 = ProcState::unused;
		// if ( p->_ofile[1]->refcnt > 1 ) p->_ofile[1]->refcnt--;
