	Buffer BufferManager::read_sync( int dev, uint64 lba )
	{
		Buffer buf		 = _get_buffer_sync( dev, lba );
		uint   offset	 = _offset_from_lba( lba );
		buf._buffer_base = (void*) ( (uint64) buf._buffer_base +
									 default_sector_size * offset );
