	}

	int BufferManager::dirt_buffer( Buffer& buf )
	{
		uint blk = buf._block_number;
		uint idx = buf._buffer_index;
		if ( blk >= block_per_pool ) return -1;
		if ( idx >= _buffer_pool[blk]._current_buffer_counts ) return -2;
		_buf_set_dirty( blk, idx );
		return 0;
	}

