		int Pipe::write( uint64 addr, int n )
		{
			int i = 0;
			Pcb * pr = k_pm.get_cur_pcb();

			_lock.acquire();
			while ( i < n )
			{
				if ( !_read_is_open || pr->is_killed() )
				{
					_lock.release();
					return -1;
				}
				if ( _data.full() )
				{ //DOC: pipewrite-full
					k_pm.wakeup( &_read_sleep );
					k_pm.sleep( &_write_sleep, &_lock );
				}
				else
				{
					char ch;
					mm::PageTable *pt = pr->get_pagetable();
					if ( mm::k_vmm.copy_in( *pt, &ch, addr + i, 1 ) == -1 )
						break;
					_data.push( ch );
					i++;
				}
			}
			k_pm.wakeup( &_read_sleep );
			_lock.release();

			return i;
		}

		int Pipe::write_in_kernel( uint64 addr, int n )
		{
			int i = 0;
			Pcb * pr = k_pm.get_cur_pcb();

			_lock.acquire();
			while ( i < n )
			{
				if ( !_read_is_open || pr->is_killed() )
				{
					_lock.release();
					return -1;
				}
				if ( _data.full())
				{ //DOC: pipewrite-full
					k_pm.wakeup( &_read_sleep );
					k_pm.sleep( &_write_sleep, &_lock );
				}
				else
				{
					char ch;
					ch = *( char* ) ( addr + i );
					_data.push( ch );
					i++;
				}
			}
			k_pm.wakeup( &_read_sleep );
			_lock.release();

			return i;
		}

