		{
			int i;
			Pcb *pr = k_pm.get_cur_pcb();
			// char ch;

			_lock.acquire();
			while ( _data.empty() && _write_is_open )
			{  //DOC: pipe-empty
				if ( pr->is_killed() )
				{
					_lock.release();
					return -1;
				}
				k_pm.sleep( &_read_sleep, &_lock ); //DOC: piperead-sleep
			}
			for ( i = 0; i < n; i++ )
			{  //DOC: piperead-copy
				if ( _data.empty() )
					break;
				unsigned char ch=_data.peek();
				_data.pop();
