			localtime->dup();

			// _root->printChildrenInfo();

			// init fat
			dentry* dev = _root->EntrySearch( "dev" );
			if ( !dev )
			{
				log_error( "RamFS::initfd: mnt is nullptr" );
				return;
			}
			dev->dup();

			char ** dev_table = new char*[ DEV_TBL_LEN ];

			for ( int i = 0; i < DEV_TBL_LEN; i++ )
